import random, time
from dataclasses import dataclass

@dataclass
class SamplingDecision:
    record: bool
    reason: str

def sampling_policy(
    session_id: str,
    has_tool_error: bool = False,
    user_feedback: str | None = None,
    duration_ms: float = 0.0,
    base_rate: float = 0.05,          # sample 5% of normal traffic
    error_rate: float = 1.0,          # always sample errors
    slow_threshold_ms: float = 3000,  # always sample slow requests
) -> SamplingDecision:
    """Tail-based sampling: decide after the request completes."""
    if has_tool_error:
        return SamplingDecision(record=True, reason="tool_error")
    if user_feedback in ("thumbs_down", "escalated"):
        return SamplingDecision(record=True, reason="negative_feedback")
    if duration_ms > slow_threshold_ms:
        return SamplingDecision(record=True, reason="slow_request")
    # Deterministic sampling by session: keeps full sessions together
    # hash the session id to a float in [0, 1)
    bucket = int(session_id.replace("-", ""), 16) % 10000 / 10000
    if bucket < base_rate:
        return SamplingDecision(record=True, reason="random_sample")
    return SamplingDecision(record=False, reason="below_rate")

# Usage after a request completes
decision = sampling_policy(
    session_id="sess-abc123",
    has_tool_error=False,
    user_feedback=None,
    duration_ms=450.0,
)
print(f"Record: {decision.record}  ({decision.reason})")
